  // \u95ee\u9898\u6587\u672c\r\n  let questionPara = Api.CreateParagraph();\r\n  questionPara.AddText(questionNumber + ". " + questionText);\r\n  questionPara.SetFontSize(12 * 2);\r\n  questionPara.SetBold(true);\r\n  questionPara.SetSpacingBefore(400);\r\n  doc.Push(questionPara);\r\n\r\n  // \u521b\u5efa\u5355\u9009\u6309\u94ae\u9009\u9879\r\n  for (let i = 0; i < options.length; i++) {\r\n    let optionPara = Api.CreateParagraph();\r\n\r\n    let radioButton = Api.CreateCheckBoxForm({\r\n      key: radioGroupName + "_option_" + String.fromCharCode(65 + i),\r\n      tip: "\u9009\u62e9\u6b64\u7b54\u6848",\r\n      required: false,\r\n      radio: true\r\n    });\r\n\r\n    // \u5c06\u6b64\u95ee\u9898\u7684\u5355\u9009\u6309\u94ae\u5206\u7ec4\r\n    radioButton.SetRadioGroup(radioGroupName);\r\n\r\n    optionPara.AddElement(radioButton);\r\n    optionPara.AddText(" " + String.fromCharCode(65 + i) + ") " + options[i]);\r\n    optionPara.SetFontSize(11 * 2);\r\n    optionPara.SetSpacingBefore(100);\r\n    doc.Push(optionPara);\r\n  }\r\n}\r\n\r\n// \u7b2c1\u9898\uff1a\u5173\u4e8e\u884c\u661f\r\ncreateQuestion(\r\n  "1",\r\n  "\u54ea\u9897\u884c\u661f\u88ab\u79f0\u4e3a\u7ea2\u8272\u661f\u7403\uff1f",\r\n  [\r\n    "\u91d1\u661f",\r\n    "\u706b\u661f",\r\n    "\u6728\u661f",\r\n    "\u571f\u661f"\r\n  ],\r\n  "Question1"\r\n);\r\n\r\n// \u7b2c2\u9898\uff1a\u5173\u4e8e\u536b\u661f\r\ncreateQuestion(\r\n  "2",\r\n  "\u54ea\u9897\u536b\u661f\u662f\u592a\u9633\u7cfb\u4e2d\u6700\u5927\u7684\u536b\u661f\uff1f",\r\n  [\r\n    "\u6728\u536b\u4e8c\uff08\u6b27\u7f57\u5df4\uff09",\r\n    "\u571f\u536b\u516d\uff08\u6cf0\u5766\uff09",\r\n    "\u6728\u536b\u4e09\uff08\u76d6\u5c3c\u7c73\u5fb7\uff09",\r\n    "\u6728\u536b\u56db\uff08\u5361\u5229\u65af\u6258\uff09"\r\n  ],\r\n  "Question2"\r\n);\r\n\r\n// \u7b2c3\u9898\uff1a\u5173\u4e8e\u6052\u661f\r\ncreateQuestion(\r\n  "3",\r\n  "\u6211\u4eec\u7684\u592a\u9633\u88ab\u5f52\u7c7b\u4e3a\u4ec0\u4e48\u7c7b\u578b\u7684\u6052\u661f\uff1f",\r\n  [\r\n    "\u7ea2\u5de8\u661f",\r\n    "\u767d\u77ee\u661f",\r\n    "\u9ec4\u77ee\u661f",\r\n    "\u84dd\u8d85\u5de8\u661f"\r\n  ],\r\n  "Question3"\r\n);\r\n\r\n// \u6dfb\u52a0\u9875\u811a\u90e8\u5206\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText("\u6d4b\u8bd5\u7ed3\u675f");\r\nparagraph.SetFontSize(12 * 2);\r\nparagraph.SetBold(true);\r\nparagraph.SetJc("center");\r\nparagraph.SetSpacingBefore(600);\r\ndoc.Push(paragraph);\r\n\r\nparagraph = Api.CreateParagraph();\r\nparagraph.AddText("\u63d0\u4ea4\u524d\u8bf7\u68c0\u67e5\u60a8\u7684\u7b54\u6848\u3002");\r\nparagraph.SetFontSize(10 * 2);\r\nparagraph.SetItalic(true);\r\nparagraph.SetJc("center");\r\ndoc.Push(paragraph);\n'})})]})}function f(r={}){const{wrapper:e}={...(0,t.R)(),...r.components};return e?(0,o.jsx)(e,{...r,children:(0,o.jsx)(d,{...r})}):d(r)}},28453:(r,e,n)=>{n.d(e,{R:()=>i,x:()=>p});var a=n(296540);const o={},t=a.createContext(o);function i(r){const e=a.useContext(t);return a.useMemo((function(){return"function"==typeof r?r(e):{...e,...r}}),[e,r])}function p(r){let e;return e=r.disableParentContext?"function"==typeof r.components?r.components(o):r.components||o:i(r.components),a.createElement(t.Provider,{value:e},r.children)}}}]);